SELECT p.id, p.consumer_id, p.title, p.content, p.cover_url, p.images, p.topic, p.ref_song_id, p.ref_song_name, p.status, p.like_count, p.comment_count, p.create_time, p.update_time, c.username AS author_name, c.avator AS author_avatar FROM post p LEFT JOIN consumer c ON p.consumer_id = c.id WHERE p.status = 1
AND p.topic = #{topic}
ORDER BY (p.like_count * 2 + p.comment_count) / (1 + TIMESTAMPDIFF(HOUR, p.create_time, NOW()) / 24.0) DESC, p.create_time DESC
ORDER BY p.create_time DESC
LIMIT #{offset}, #{limit}

SELECT p.id, p.consumer_id, p.title, p.content, p.cover_url, p.images, p.topic, p.ref_song_id, p.ref_song_name, p.status, p.like_count, p.comment_count, p.create_time, p.update_time, c.username AS author_name, c.avator AS author_avatar FROM post p INNER JOIN follow f ON p.consumer_id = f.follow_user_id LEFT JOIN consumer c ON p.consumer_id = c.id WHERE f.user_id = #{userId} AND p.status = 1
AND p.topic = #{topic}
ORDER BY (p.like_count * 2 + p.comment_count) / (1 + TIMESTAMPDIFF(HOUR, p.create_time, NOW()) / 24.0) DESC, p.create_time DESC
ORDER BY p.create_time DESC
LIMIT #{offset}, #{limit}

